import React from 'react';
import { BrowserRouter as Router, Routes } from 'react-router-dom'; // Import Navigate

import MasterLayout from '../../layouts/admin/MasterLayout';

function App()
{
  return (
    <div className="App">
      <Router>
        <Routes>
          <Route path="/admin/dashboard" name="Admin" element={<MasterLayout />} />

        </Routes>
      </Router>
    </div>
  );
}

export default App;
